export default {

	async auditLog(action, entity_type, entity_id, payload) {
		try {
			await qAuditLogInsert.run({
				action,
				entity_type,
				entity_id: entity_id ?? "",
				actor_member_id: appsmith.store.facilitator_id ?? "",
				actor_email: ((appsmith.user?.email ?? "").trim().toLowerCase()),
				mode: appsmith.mode ?? "",
				details_json: JSON.stringify(payload ?? {}),
			});
		} catch (e) {
						console.log("audit_log insert failed:", e);
					}
	},

	async refresh() {
		await Promise.allSettled([
      qMemberById.run(),
      qMemberAgreements.run(),
      qMemberReleases.run(),
      qMembersDirectory.run(),
			qMemberDonations.run(),
      // If you want facilitator dropdown populated on load:
      qListFacilitators?.run?.(),
			qAgreementTypesList.run(),
			qAgreementTemplatesByType.run({
      	type_key: selAgreementType.selectedOptionValue,
    	}),
    ]);	
  },

	async refreshAgreements() {
    if (!selAgreementType.selectedOptionValue) {
				return null;
    }

    return await qAgreementTemplatesByType.run({
      type_key: selAgreementType.selectedOptionValue,
    });
  },

	_requireMemberId() {
    let memberId = selMember?.selectedOptionValue;

    if (!memberId) {
			if(!appsmith.URL.queryParams.member_id ) {
				showAlert("Select a member first.", "warning");
				return null;
			}
			memberId = appsmith.URL.queryParams.member_id;
			selMember.setSelectedOption(memberId);
		}

		return memberId;
  },

  _requireFacilitator() {
    const facilitatorId = inpFacilitator?.selectedOptionValue;
    if (!facilitatorId) {
      showAlert("Please select a facilitator before creating an agreement.", "warning");
      return null;
    }

		storeValue("facilitator_id", facilitatorId);
    return facilitatorId;
  },

	 _requireAgreementTemplate() {
    const agreementTemplateId = selAgreementTemplate?.selectedOptionValue;
    if (!agreementTemplateId) {
      showAlert("Please select an Agreement Type and Template before creating an agreement.", "warning");
      return null;
    }

		storeValue("agreement_template_id", agreementTemplateId);
    return agreementTemplateId;
  },

  async setMemberId(formMemberId) {

		const memberId = formMemberId || this._requireMemberId();
		storeValue("member_id", memberId);	

		this.refresh();

		return memberId;
  },	

	/* Not needed...
	resetAllWidgets: () => {
    resetWidget('inpCreated', true);
    resetWidget('inpStatus', true);
    resetWidget('inpRoles', true);
    // Add other widgets as needed
  },
	*/

  async init() {

		try {
			//showAlert("Beginning init. mode=" + appsmith.mode, "warning");

			// Wait briefly for Appsmith user context to hydrate
      let email = null;
      for (let i = 0; i < 20; i++) {
        email = (appsmith.user?.email ?? "").trim().toLowerCase();
        if (email) break;
        await new Promise(r => setTimeout(r, 150));
      }

			if (!email) {
				showAlert("Unknown user: appsmith.user.email not available.", "error");
				return;
			}

			// IMPORTANT: use return value of run(), not qCurrentFacilitator.data
      let rows = await qCurrentFacilitator.run({ email });

      // 🔴 Appsmith bug fix
      if (!Array.isArray(rows)) rows = [];
      //showAlert("qCurrentFacilitator rows=" + rows.length, "warning");

      const me = rows[0];	

			if (!me?.member_id) {
				showAlert("Access denied: not an active facilitator for " + email, "error");

				await this.auditLog("auth.denied","facilitator","", { email, page: appsmith.URL?.pathname, mode: appsmith.mode });if (appsmith.mode === "DEPLOYED" || appsmith.mode === "PUBLISHED") {
					//Only redirect when not in editor
					navigateTo("Unauthorized", {}, "SAME_WINDOW");
				}
				return;
			}

			const facilitator_id = me.member_id;
			const facilitator_email = (me.email ?? "").trim().toLowerCase();
			const is_document_reviewer = me.is_document_reviewer;
			const is_donations_reviewer = me.is_donations_reviewer;

			//showAlert("Access granted for " + facilitator_email + " id=" + facilitator_id + " document reviewer=" + is_document_reviewer + " donations reviewer=" + is_donations_reviewer, "success");

			// May want these enabled in deployed mode:
			storeValue("facilitator_id", facilitator_id);
			storeValue("facilitator_email", facilitator_email);
			storeValue("facilitator_is_reviewer", is_document_reviewer );
			storeValue("facilitator_is_donations_reviewer", is_donations_reviewer);
			storeValue("facilitator_full_name", `${me.first_name} ${me.last_name}`.trim());	

			//showAlert("Access granted for " + appsmith.store.facilitator_email + " id=" + appsmith.store.facilitator_id + " document reviewer=" + appsmith.store.facilitator_is_reviewer + " donations reviewer=" + appsmith.store.facilitator_is_donations_reviewer, "success");

			//await this.auditLog("auth.granted","facilitator", facilitator_id, { email: facilitator_email, is_reviewer, is_donations_reviewer page: appsmith.URL?.pathname, mode: appsmith.mode });
		} catch (e) {
			showAlert("Access check failed: " + (e?.message || e), "error");
			// Helpful: show query error if present
			showAlert("Query error: " + JSON.stringify(qCurrentFacilitator?.error ?? {}), "error");
			if (appsmith.mode === "DEPLOYED" || appsmith.mode === "PUBLISHED") {
				//Only redirect when not in editor
				navigateTo("Unauthorized", {}, "SAME_WINDOW");
			}
			return;
		}

		storeValue("NC_PUBLIC_URL", "https://nocodb.danks.store");

		return this.setMemberId();

	},

	_normalizeUploadResponse(uploadRes) {
		const r = uploadRes?.data ?? uploadRes;

		const arr =
			Array.isArray(r) ? r :
			Array.isArray(r?.files) ? r.files :
			(r && typeof r === "object") ? [r] :
			[];

		// Require real attachment objects (path or signedPath)
		const good = arr.filter(x => x && (x.path || x.signedPath));

		if (!good.length) {
			console.log("Unexpected upload response:", uploadRes);
			throw new Error("Upload succeeded but did not return attachment path(s).");
		}

		return good;
	},

	async sendDigitalAgreement() {
		const memberId = this._requireMemberId();
		const facilitatorId = this._requireFacilitator();
		const agreementTemplateId = this._requireAgreementTemplate();		

		if (!facilitatorId) {
			showAlert("Invalid Facilitator.", "error");			
			return;
		}
		if (!agreementTemplateId) {
			showAlert("Invalid Member.", "error");
			return;
		}
		if (!memberId) {
			showAlert("Invalid Agreement Template.", "error");
			return;
		}		
		//showAlert("Creating Digital Agreement in SQL.", "success");

		// 1) Create the pending agreement record first
		const createRes = await qCreatePendingAgreement.run({
			member_id: memberId,
			facilitator_id: facilitatorId,
			signature_method: "documenso",
			agreement_template_id: agreementTemplateId,
			status: "pending_email_send",
			evidence_json: "[]",
		});

		//showAlert("Normalizing Agreement.", "success");
		// 2) Normalize returned agreement id
		const agreementId =
			(typeof createRes === "string" && createRes) ||
			createRes?.member_agreement_id ||
			createRes?.[0]?.member_agreement_id ||
			createRes?.[0]?.member_agreements_id || // just in case naming differs
			null;

		if (!agreementId) {
			showAlert("Agreement created, but no member_agreement_id was returned.", "error");
			return;
		}

		showAlert("Digital release queued (pending email send).", "success");

		// 3) Trigger n8n webhook with a JSON body
		const triggerRes = await apiTriggerDocumenso.run({
			member_agreement_id: agreementId,
			// optional but useful for logs / idempotency
			externalId: `ma:${agreementId}`,
		});

		showAlert("Email sent.", "success");

		// 4) Refresh UI
		await qMemberAgreements.run();
		resetWidget("FilePicker1", true);

		return { agreementId, triggerRes };
	},

  async openPaperUpload() {
		const memberId = this._requireMemberId();
		const facilitatorId = this._requireFacilitator();
		const agreementTemplateId = this._requireAgreementTemplate();		

		if (!facilitatorId) {
			showAlert("Invalid Facilitator.", "error");			
			return;
		}
		if (!agreementTemplateId) {
			showAlert("Invalid Member.", "error");
			return;
		}
		if (!memberId) {
			showAlert("Invalid Agreement Template.", "error");
			return;
		}		

		const raw = FilePicker1?.selectedFiles?.length
    ? FilePicker1.selectedFiles
    : (FilePicker1?.files || []);

		console.log("FilePicker1.selectedFiles raw:", raw);

		//showAlert(`Raw files length: ${(FilePicker1?.selectedFiles ?? []).length}`, "info");
    // Only keep real File-like objects
    const files = raw.filter((f) =>
      f &&
      typeof f === "object" &&
      typeof f.name === "string" &&
      typeof f.size === "number" &&
      f.size >= 0
    );

		if (!files.length) {
			showAlert("Please choose at least one valid file to upload for the paper agreement.", "warning");
			return;
		}

    // If there were invalid entries, surface it loudly (this is what you're hitting)
    if (files.length !== raw.length) {
      showAlert(
        `Some selected items were invalid (null/non-file). Remove them and re-select the file(s).`,
        "warning"
      );
      // Stop here so you don't get silent partial uploads
      return;
    }

		// Optional: guard against non-File objects
		const bad = files.find(f => typeof f !== "object" || !("name" in f) || !("size" in f));
		if (bad) {
			console.log("Bad file entry:", bad, raw);
			showAlert("One of the selected items isn't a valid file. Try removing it and re-selecting files.", "error");
			return;
		}

		showAlert(`Uploading ${files.length} file(s)...`, "info");	

		// N8N Method - Use Base64 in FilePicker
		try {		
			const uploadRes = await apiUploadEvidenceViaN8n.run();
			// uploadRes should be {ok, files} where files is an attachment array from NocoDB
			const attachments = uploadRes.files;

		/* NocoDB Method - Use Binary in FilePicker
		// 1) Upload files to NocoDB storage
			const attachments = [];

			for (const f of files) {
				// apiUploadEvidence must use {{this.params.files}} in bodyFormData
				console.log("About to upload, files param:", { files: [f] });
				console.log("About to upload, complete upload array:", FilePicker1?.Selectedfiles );
				console.log("About to upload, raw filtered:", files );
				const uploadRes = await apiUploadEvidence.run({ files: [f] });
				//const uploadRes = await apiUploadEvidence.run({ files: FilePicker1.files });
				console.log("Got back from apiUploadEvidence:", uploadRes );
				const normalized = this._normalizeUploadResponse(uploadRes);
				console.log("Got back from _normalizeUploadResponse:", normalized );
				// normalized is expected to be an array
				if (Array.isArray(normalized)) attachments.push(...normalized);
				else if (normalized) attachments.push(normalized);
			}
*/

			const evidenceJson = JSON.stringify(attachments);

			// 2) Create the agreement record in pending_review with evidence attached
			const ins = await qCreatePendingAgreement.run({
				member_id: memberId,
				facilitator_id: facilitatorId,
				agreement_template_id: agreementTemplateId,				
				signature_method: "paper",
				status: "pending_review",
				evidence_json: evidenceJson,
			});

			// Audit: paper agreement created with evidence (SQL update happens here, after HTTP upload)
			const _agId = ins?.[0]?.member_agreement_id || ins?.member_agreement_id || "";
			await this.auditLog("member_agreement.created","member_agreement", _agId, { member_id: memberId, facilitator_id: facilitatorId, agreement_template_id: agreementTemplateId, signature_method: "paper", status: "pending_review" });
			await this.auditLog("member_agreement.evidence_uploaded","member_agreement", _agId, { member_id: memberId, facilitator_id: facilitatorId, agreement_template_id: agreementTemplateId, attachments: Array.isArray(attachments) ? attachments.length : 0 });
			showAlert("Paper agreement uploaded and queued for review.", "success");

			// 3) Refresh UI
			await qMemberAgreements.run();
      resetWidget("FilePicker1", true);

			return { attachments, ins };

		} catch (e) {
			console.error("Paper upload failed:", e);
			showAlert(`Upload failed: ${e?.message ?? e}`, "error");
			throw e; // so you can see it in Appsmith errors too
		}			
  },

	evidenceLinks(evidenceCell) {
		// evidenceCell might be:
		// - an array of file objects
		// - a JSON string
		// - null
		// - or even nested like [[{...},{...}], [{...}]] depending on your query/table mapping
		const base = (appsmith.store.NC_PUBLIC_URL || "").replace(/\/+$/, "");
		if (!base) return "<span style='color:#999'>Set NC_PUBLIC_URL</span>";

		let ev = evidenceCell;

		// If it's a string, try parse
		if (typeof ev === "string") {
			try { ev = JSON.parse(ev); } catch (e) { /* ignore */ }
		}

		// Normalize:
		// If it's nested arrays, flatten to a single array of file objects.
		if (Array.isArray(ev) && Array.isArray(ev[0])) {
			ev = ev.flat();
		}

		if (!Array.isArray(ev) || ev.length === 0) return "";

		const esc = (s) => String(s ?? "")
			.replaceAll("&", "&amp;")
			.replaceAll("<", "&lt;")
			.replaceAll(">", "&gt;")
			.replaceAll('"', "&quot;")
			.replaceAll("'", "&#39;");

		// Build "buttons" as <a> tags styled like buttons
		return ev
// Use for signed paths
//			.filter(f => f && (f.signedPath || f.path))
				.filter(f => f && f.path)
			.map((f, idx) => {
// Use for signed paths
//				const href = `${base}/${f.signedPath || f.path}`; // prefer signedPath
				const href = `${base}/${f.path}`;
				const label = esc(f.title || `File ${idx + 1}`);
				return `<a
					href="${esc(href)}"
					target="_blank"
					rel="noopener noreferrer"
					style="
						display:inline-block;
						margin:2px 6px 2px 0;
						padding:4px 8px;
						border:1px solid #ccc;
						border-radius:6px;
						text-decoration:none;
						font-size:12px;
						color:#111;
						background:#f7f7f7;
					"
				>⬇ ${label}</a>`;
			})
			.join("");
	},

	async verifyAgreement(agreementId, reviewNotes, newStatus, memberId, rowEvidence, agreementType) {

		let ApprovedRejected = "approved";
		if(newStatus.trim() == "rejected") {ApprovedRejected = "rejected";}

		await qVerifyAgreement.run({ member_agreement_id: agreementId, review_notes: reviewNotes, new_status: newStatus });
		await memberProfile.auditLog("agreement." + ApprovedRejected, "member_agreement", agreementId, {
			member_id: memberId || appsmith.store.member_id,
			status: newStatus,
			review_notes: reviewNotes,
			evidence: rowEvidence,
			agreement_type: agreementType
		});
		await qMemberAgreements.run();

		showAlert("Agreement " + ApprovedRejected + ".", "success");

	},	

	async verifyDonation(donationId, reviewNotes, newStatus, memberId, amountCents, donatedAt) {

  	await qVerifyDonation.run({ donation_id: donationId, review_notes: reviewNotes, new_status: newStatus  });
  	await memberProfile.auditLog("donation." + newStatus, "donation", donationId, {
    		member_id: memberId || appsmith.store.member_id,
    		status: newStatus,
    		review_notes: reviewNotes,
    		amount_cents: amountCents,
    		donated_at: donatedAt
  	});
  	await qMemberDonations.run();

		showAlert("Donation " + newStatus + ".", "success");

	},

	async voidRelease(voidReleaseId, voidReleaseType, voidReason, mushroomProcessId, airtableRecordId) {

    if (voidReleaseType === "sacrament_release") {
			// 1) Mark UNshipped in Airtable (only if sacrament_release)
			await apiMarkProductUnShipped.run({
				airtable_record_id: airtableRecordId,
				mushroomprocess_product_id: mushroomProcessId,
			});
    }

		if (!voidReleaseId) {
			showAlert("Please choose a release to void.", "warning");
			return;			
		}

		const voided = await qVoidRelease.run({
      void_reason: voidReason || "Voided by: " + appsmith.store.facilitator_full_name,
			sacrament_release_id: voidReleaseId
		});

		showAlert(`Release voided: ${voided?.[0]?.sacrament_release_id || "ok"}`, "success");
		await this.auditLog("release.voided","release", voided?.[0]?.sacrament_release_id, {
			void_reason: voidReason,
			release_type: voidReleaseType,
			sacrament_release_id: voidReleaseId,
			voided_by: appsmith.store.facilitator_id,
      mushroomprocess_product_id: mushroomProcessId|| null,
			storage_locaton: (appsmith.store.facilitator_is_reviewer || appsmith.store.facilitator_is_reviewer == "true" )  ? "Products Storage" : appsmith.store.facilitator_full_name,
		});

		return voided;
	},

  _normText(v) {
    if (v === null || v === undefined) return "";
    return String(v).trim();
  },

  _normEmail(v) {
    return this._normText(v).toLowerCase();
  },

	_toDateOnly(v) {
		if (v === null || v === undefined) return "";
		const s = String(v).trim();
		if (!s) return "";

		// If it's already YYYY-MM-DD, keep it
		if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;

		// If it's ISO datetime, parse and convert to YYYY-MM-DD (UTC-safe)
		const d = new Date(s);
		if (isNaN(d.getTime())) return "";

		return d.toISOString().slice(0, 10); // YYYY-MM-DD
	},

  _diff(oldObj, newObj) {
    const changes = {};
    for (const k of Object.keys(newObj)) {
      const a = oldObj?.[k];
      const b = newObj?.[k];

      // Normalize null/undefined/"" equivalence for diff readability
      const na = (a === null || a === undefined) ? "" : String(a);
      const nb = (b === null || b === undefined) ? "" : String(b);

      if (na !== nb) changes[k] = { from: a ?? null, to: b ?? null };
    }
    return changes;
  },


  async submitMemberUpdate() {
    const memberId = this._requireMemberId();
    if (!memberId) return;

    // Use whatever query you already have that loads the member
    const oldRow = (qMemberById?.data && qMemberById.data[0]) ? qMemberById.data[0] : {};

		//showAlert("oldRow raw " + oldRow,"info");
    /*
    const ui = {
      first_name: this._normText(inpFirstName?.text ?? oldRow.first_name),
      last_name: this._normText(inpLastName?.text ?? oldRow.last_name),
      email: this._normEmail(inpEmail?.text ?? oldRow.email),
      phone: this._normText(inpPhone?.text ?? oldRow.phone),
      date_of_birth: this._toDateOnly(inpDOB?.selectedDate.text ?? oldRow.date_of_birth),
      notes: this._normText(inpNotes?.text ?? oldRow.notes),
    //  status: this._normText(selMemberStatus?.selectedOptionValue ?? oldRow.status ?? "active"),
    };*/
		const ui = {
			first_name: String(inpFirstName.text || "").trim(),
			last_name: String(inpLastName.text || "").trim(),
			email: String(inpEmail.text || "").trim().toLowerCase(),
			phone: String(inpPhone.text || "").trim(),
			date_of_birth: this._toDateOnly(inpDOB.selectedDate || ""),  // let SQL cast
			notes: String(inpNotes.text || "").trim(),
		//  status: String(selStatus.selectedOptionValue || ""),
		};

    // Compute changes for audit log
    const changes = this._diff(
      {
        first_name: oldRow.first_name ?? "",
        last_name: oldRow.last_name ?? "",
        email: (oldRow.email ?? "").toLowerCase(),
        phone: oldRow.phone ?? "",
        date_of_birth: oldRow.date_of_birth ?? "",
        notes: oldRow.notes ?? "",
  //      status: oldRow.status ?? "",
      },
      ui
    );

    if (Object.keys(changes).length === 0) {
      showAlert("No changes to save.", "info");
      return;
    }

		//showAlert("ui raw " + ui,"info");
		//console.log("ui types", Object.fromEntries(Object.entries(ui).map(([k,v]) => [k, typeof v])));

    // Update DB
    const res = await qMemberUpdate.run({
      member_id: memberId,
      ...ui,
    });

    showAlert("Member updated.", "success");

    // Audit log (re-uses your existing helper)
    await this.auditLog("member.updated", "member", memberId, {
      member_id: memberId,
      changes,
      updated_from_page: "Members - Profile",
    });

    // Refresh the page data
    this.refresh();

    return res;
  },	
};

