actionConfiguration.body:
async function () {
  const memberId = memberProfile._requireMemberId();
  const facilitatorId = memberProfile._requireFacilitator();
  const agreementTemplateId = memberProfile._requireAgreementTemplate();
  if (!facilitatorId) {
    showAlert("Invalid Facilitator.", "error");
    return;
  }
  if (!agreementTemplateId) {
    showAlert("Invalid Member.", "error");
    return;
  }
  if (!memberId) {
    showAlert("Invalid Agreement Template.", "error");
    return;
  }
  const createRes = await qCreatePendingAgreement.run({
    member_id: memberId,
    facilitator_id: facilitatorId,
    signature_method: "documenso",
    agreement_template_id: agreementTemplateId,
    status: "pending_email_send",
    evidence_json: "[]"
  });
  const agreementId = typeof createRes === "string" && createRes || createRes?.member_agreement_id || createRes?.[0]?.member_agreement_id || createRes?.[0]?.member_agreements_id || null;
  if (!agreementId) {
    showAlert("Agreement created, but no member_agreement_id was returned.", "error");
    return;
  }
  showAlert("Digital release queued (pending email send).", "success");
  const triggerRes = await apiTriggerDocumenso.run({
    member_agreement_id: agreementId,
    externalId: `ma:${agreementId}`
  });
  showAlert("Email sent.", "success");
  await qMemberAgreements.run();
  resetWidget("FilePicker1", true);
  return {
    agreementId,
    triggerRes
  };
}

