function (oldRow, newRow) {
  const changes = {};
  const keys = ["name", "version", "required_for", "doc_url", "active", "documenso_template_envelope_id", "documenso_member_recipient_id", "documenso_facilitator_recipient_id"];
  for (const k of keys) {
    let oldV = oldRow?.[k];
    let newV = newRow?.[k];
    if (k === "required_for") {
      oldV = agreementTemplateFlows._normArray(oldV);
      newV = agreementTemplateFlows._normArray(newV);
    } else if (k === "documenso_member_recipient_id" || k === "documenso_facilitator_recipient_id") {
      oldV = agreementTemplateFlows._normInt(oldV);
      newV = agreementTemplateFlows._normInt(newV);
    } else if (k === "documenso_template_envelope_id" || k === "doc_url" || k === "name" || k === "version") {
      oldV = agreementTemplateFlows._normText(oldV);
      newV = agreementTemplateFlows._normText(newV);
    } else if (k === "active") {
      oldV = !!oldV;
      newV = !!newV;
    }
    const same = JSON.stringify(oldV ?? null) === JSON.stringify(newV ?? null);
    if (!same) changes[k] = {
      from: oldV ?? null,
      to: newV ?? null
    };
  }
  return changes;
}

