async function (row, multiselect) {
  const templates = qAgreementTemplatesList?.data || [];
  const isExisting = !!row?.agreement_template_id;
  const oldRow = isExisting ? templates.find(t => t.agreement_template_id === row.agreement_template_id) : null;
  if (multiselect) {
    row.required_for = multiselect;
  }
  const requiredForArr = agreementTemplateFlows._normArray(row.required_for);
  const normalizedRow = {
    ...row,
    required_for: requiredForArr,
    documenso_template_envelope_id: agreementTemplateFlows._normText(row.documenso_template_envelope_id),
    documenso_member_recipient_id: agreementTemplateFlows._normInt(row.documenso_member_recipient_id),
    documenso_facilitator_recipient_id: agreementTemplateFlows._normInt(row.documenso_facilitator_recipient_id)
  };
  const changes = agreementTemplateFlows._diff(oldRow, normalizedRow);
  if (isExisting && Object.keys(changes).length === 0) {
    showAlert("No changes to save.", "info");
    return;
  }
  const auditDetails = {
    agreement_template_id: row.agreement_template_id ?? null,
    changes,
    saved_from_page: "Agreements - Templates"
  };
  const params = {
    agreement_template_id: row.agreement_template_id,
    name: agreementTemplateFlows._normText(row.name),
    version: agreementTemplateFlows._normText(row.version),
    required_for_json: JSON.stringify(requiredForArr),
    doc_url: agreementTemplateFlows._normText(row.doc_url),
    active: !!row.active,
    documenso_template_envelope_id: agreementTemplateFlows._normText(row.documenso_template_envelope_id),
    documenso_member_recipient_id: (normalizedRow.documenso_member_recipient_id ?? "").toString(),
    documenso_facilitator_recipient_id: (normalizedRow.documenso_facilitator_recipient_id ?? "").toString(),
    actor: appsmith.store.facilitator_email || appsmith.user?.email || "unknown",
    audit_details: JSON.stringify(auditDetails)
  };
  if (!params.name) throw new Error("Template name is required.");
  if (!params.version) throw new Error("Template version is required.");
  let res;
  if (isExisting) {
    res = await qAgreementTemplateUpdate.run(params);
    showAlert("Template updated.", "success");
  } else {
    res = await qAgreementTemplateInsert.run(params);
    showAlert("Template created.", "success");
  }
  await qAgreementTemplatesList.run();
  return res;
}

